  ('locality-e3452428-moex-00104', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '依中央行政機關組織基準法規定，下列何者非屬行政機關？', '["衛生福利部少子女化對策辦公室", "國防部軍備局", "勞動部勞動力發展署", "行政院主計總處"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00105', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於行政機關管轄之敘述，下列何者錯誤？', '["行政機關之管轄，必須依法規，當事人不得協議變更", "數機關對同一事件均有管轄權時，無論受理該事件之先後次序，皆應尊重機關間之協議，以決 定管轄權歸屬", "職務協助未變更或移轉事件之管轄權", "無隸屬關係之機關，彼此間管轄權之變動，稱之為委託"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00106', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '下列何者為公務員服務法之適用對象？', '["公立醫院約聘僱醫師", "台灣電力股份有限公司董事長", "公立學校未兼任行政職務教師", "直轄市議會議長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00107', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於行政訴訟之訴訟費用，下列敘述何者錯誤？', '["一般訴訟程序之上訴，徵收新臺幣6,000元之裁判費", "通常訴訟程序及都市計畫審查程序事件之上訴審律師酬金，經法院裁定得列為訴訟費用", "對於上訴審判決提起再審，再審裁判費與上訴裁判費相同", "發回更審後再行上訴，其上訴裁判費減半徵收"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00108', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '關於公務員法律責任之敘述，下列何者錯誤？', '["公務員懲戒案件現已從公務員懲戒委員會改制為懲戒法院所審理", "公務員執行職務所涉及之損害賠償責任僅得依據民法規定處理", "依據刑法規定公務員若犯準職務罪時將會加重其刑罰", "依據公務員懲戒法之規定，對於受懲戒之公務員得科以罰款"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00109', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '法規命令係由法律授權主管機關訂定，惟立法院仍得對之進行監督。下列敘述何者錯誤？', '["各機關基於法律授權訂定之命令，於發布後，應即送立法院", "依立法院職權行使法之規定，立法院審查時得通過議決，通知行政機關廢止", "立法院應以三讀程序之決議通知機關更正之", "立法院不得以決議逕行將命令變更 30840、31140 31640、31740 31940"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00110', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '國立大學為確保學生具有一定之專業能力，授權各系所訂定考試規則，以明定系所學生取得學分 之條件，下列何者為考試規則之合憲性依據？', '["平等原則", "大學自治", "住民自治", "誠信原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00111', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '有關行政處分無效事由之敘述，下列何者錯誤？', '["未經授權而違背法規有關管轄之規定，主要係指欠缺事物管轄及土地管轄之情形", "所要求或許可之行為構成犯罪者，係指該行為客觀上違反刑罰之法規，而具有違法性", "應以證書方式作成而未給予證書者，係指凡行政處分應依法定方式作成而有所欠缺者", "不能得知處分機關，係指經由形式觀察，無法得知處分機關之情形"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00112', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '行政機關為達成行政目的，得於行政處分作成時附加附款，下列何者非屬此種附款？', '["經濟部核准甲設定礦業權之申請，惟於同意登記設立礦業權通知函中，註明「如出現重大環境 保護之必要或者發生其他重大土地開發事由，得註銷本設定登記」", "A直轄市政府核准乙設立工廠之申請，並於核准函中附加「每年應提供至少新臺幣50萬元回 饋金」條款", "B縣警察局核准丙示威遊行之申請，惟要求遊行路線須避開活動最後主場之火車站站前廣場", "國家通訊傳播委員會核准丁換發營運執照之申請，核發自發照日起5年為限之營運執照"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL),
  ('locality-e3452428-moex-00113', 'locality-e3452428', 'locality-e3452428-moex-113-3082b5f1', 'sub-locality-e3452428-04', NULL, 'single_choice', '主管機關 A 認定甲所有之房屋為程序違建，乃對甲寄發違章建築補辦手續通知單（下稱補辦通 知單），限期檢齊文件補辦建造執照，如逾期未補辦將進行拆除。甲逾期未補辦，A機關乃寄發 違章建築拆除通知單（下稱拆除通知單），通知甲限期拆除該房屋。如甲未依期限拆除，A機關 決定代行拆除，再向甲徵收費用，前述2件通知單何者可作為執行名義？', '["僅補辦通知單可作為執行名義", "僅拆除通知單可作為執行名義", "2件通知單均具下命性質而屬行政處分，均可為執行名義", "A機關依法須另為催告，2件通知單均不得作為執行名義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:18+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "8f16fb1f4652", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "501", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般民政"}'::jsonb, NULL)
